import axios from 'axios';
import config from '../config/api';

const CURRENT_USER_KEY = 'currentUser';

export const userService = {
    register: async (userData) => {
        const formData = new FormData();
        formData.append('name', userData.name);
        formData.append('email', userData.email);
        formData.append('password', userData.password);
        const res = await axios.post(`${config.API_URL}/auth/register`, formData);
        return res.data;
    },

    login: async (email, password) => {
        const formData = new FormData();
        formData.append('email', email);
        formData.append('password', password);
        const res = await axios.post(`${config.API_URL}/auth/login`, formData);
        const user = res.data;
        localStorage.setItem(CURRENT_USER_KEY, JSON.stringify(user));
        return user;
    },

    logout: () => {
        localStorage.removeItem(CURRENT_USER_KEY);
    },

    getCurrentUser: () => {
        const user = localStorage.getItem(CURRENT_USER_KEY);
        return user ? JSON.parse(user) : null;
    },

    getUser: async (userId) => {
        const res = await axios.get(`${config.API_URL}/users/${userId}`);
        return res.data;
    },

    updateProfile: async (userId, profileData) => {
        const res = await axios.put(`${config.API_URL}/users/${userId}`, profileData);
        // also update local copy
        const current = JSON.parse(localStorage.getItem(CURRENT_USER_KEY) || '{}');
        if (current?.id === userId) {
            localStorage.setItem(CURRENT_USER_KEY, JSON.stringify(res.data));
        }
        return res.data;
    }
};
